import { useFirebase } from '../context/FirebaseContext';
import { addDoc, updateDoc, deleteDoc, doc, collection } from 'firebase/firestore';
import { db } from '../firebase/config';
import { Raffle } from '../types';
import CarSpecificationsForm from '../components/admin/CarSpecificationsForm';
import CompaniesManager from '../components/admin/CompaniesManager';
import DatabaseMigration from '../components/admin/DatabaseMigration';
import AppSettingsForm from '../components/admin/AppSettingsForm';
import CarSpecificationsModal from '../components/CarSpecificationsModal';
import AdminsManager from '../components/admin/AdminsManager';
import { useUser } from '../context/UserContext';

const AdminHeader = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(3),
  borderRadius: theme.spacing(2),
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: theme.spacing(3),
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: 'white',
  boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
}));

const StatsCard = styled(Card)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  height: '100%',
  transition: 'transform 0.2s ease, box-shadow 0.2s ease',
  '&:hover': {
    transform: 'translateY(-5px)',
    boxShadow: '0 8px 24px rgba(0,0,0,0.1)',
  },
}));

const StatsIcon = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 60,
  height: 60,
  borderRadius: '50%',
  marginBottom: theme.spacing(2),
  backgroundColor: alpha(theme.palette.primary.main, 0.1),
  color: theme.palette.primary.main,
}));

const TablePaper = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  overflow: 'hidden',
  boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  marginBottom: theme.spacing(4),
}));

// Компонент для панели с разными вкладками
const TabPanel = (props: { children?: React.ReactNode; index: number; value: number }) => {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`admin-tabpanel-${index}`}
      aria-labelledby={`admin-tab-${index}`}
      style={{ padding: '16px 0' }}
      {...other}
    >
      {value === index && children}
    </div>
  );
};

// Создаем компоненты-обертки для замены Grid
interface GridContainerProps {
  children: React.ReactNode;
  spacing?: number;
  sx?: any;
  [key: string]: any;
}

const GridContainer: React.FC<GridContainerProps> = ({ children, spacing = 0, ...props }) => (
  <Box 
    sx={{ 
      display: 'flex', 
      flexWrap: 'wrap', 
      margin: spacing ? `-${spacing * 4}px` : 0,
      width: spacing ? `calc(100% + ${spacing * 8}px)` : '100%',
      ...props.sx
    }}
    {...props}
  >
    {children}
  </Box>
);

interface GridItemProps {
  children: React.ReactNode;
  xs?: number;
  md?: number;
  sx?: any;
  [key: string]: any;
}

const GridItem: React.FC<GridItemProps> = ({ children, xs, md, ...props }) => {
  // Определяем ширину в зависимости от брейкпоинтов
  const widthStyles: Record<string, string> = {};
  
  if (xs) {
    widthStyles.xs = xs === 12 ? '100%' : `${(xs / 12) * 100}%`;
  }
  
  if (md) {
    widthStyles.md = md === 12 ? '100%' : `${(md / 12) * 100}%`;
  }
  
  return (
    <Box 
      sx={{ 
        padding: 2,
        boxSizing: 'border-box',
        flexShrink: 0,
        ...props.sx,
        width: { xs: '100%', ...widthStyles }
      }}
      {...props}
    >
      {children}
    </Box>
  );
};

const AdminPage: React.FC = () => {
  const theme = useTheme();
  const { raffles, companies, refreshData } = useFirebase();
  const { profile } = useUser();
  const [tabValue, setTabValue] = useState(0);
  const [openDialog, setOpenDialog] = useState(false);
  const [editRaffle, setEditRaffle] = useState<Raffle | null>(null);
  const [openCarSpecsDialog, setOpenCarSpecsDialog] = useState(false);
  const [selectedRaffle, setSelectedRaffle] = useState<Raffle | null>(null);
  const [viewCarSpecsModal, setViewCarSpecsModal] = useState(false);
  const [form, setForm] = useState<any>({
    title: '',
    image: '',
    description: '',
    totalTickets: '',
    ticketsSold: 0,
    price: '',
    status: 'draft',
    endDate: '',
    companyId: '',
    year: '',
    participants: 0
  });
  
  // Проверка, является ли пользователь суперадминистратором
  const isSuperAdmin = profile?.role === 'superadmin';
  // Проверка, является ли пользователь администратором компании
  const isCompanyAdmin = profile?.role === 'admin' && profile?.companyId;
  // ID компании администратора
  const adminCompanyId = profile?.companyId;
  
  // Данные статистики
  const statsData = [
    { 
      title: 'Всего розыгрышей', 
      value: raffles.length, 
      icon: <CardGiftcard sx={{ fontSize: 30 }} />,
      change: `${raffles.filter(r => r.status === 'active').length} активных`
    },
    { 
      title: 'Активных участников', 
      value: raffles.reduce((sum, raffle) => sum + (raffle.participants || 0), 0), 
      icon: <People sx={{ fontSize: 30 }} />,
      change: 'Все розыгрыши'
    },
    { 
      title: 'Продано билетов', 
      value: raffles.reduce((sum, raffle) => sum + raffle.ticketsSold, 0), 
      icon: <MonetizationOn sx={{ fontSize: 30 }} />,
      change: 'Все розыгрыши'
    },
  ];
  
  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };
  
  // Открыть диалог создания/редактирования
  const handleOpenDialog = (raffle?: any) => {
    if (raffle) {
      setEditRaffle(raffle);
      setForm({ ...raffle });
    } else {
      setEditRaffle(null);
      setForm({
        title: '', image: '', description: '', totalTickets: '', ticketsSold: 0, price: '', status: 'draft', endDate: '', companyId: '', year: '', participants: 0
      });
    }
    setOpenDialog(true);
  };
  
  // Закрыть диалог
  const handleCloseDialog = () => {
    setOpenDialog(false);
    setEditRaffle(null);
  };
  
  const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | { name?: string; value: unknown }>) => {
    const name = e.target.name as string;
    const value = e.target.value;
    setForm({ ...form, [name]: value });
  };
  
  const handleSelectChange = (e: SelectChangeEvent) => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
  };
  
  const handleSaveRaffle = async () => {
    try {
      const raffleData = {
        ...form,
        totalTickets: parseInt(form.totalTickets),
        price: parseFloat(form.price),
        year: parseInt(form.year)
      };
      
      if (editRaffle) {
        // Update existing raffle
        const raffleRef = doc(db, 'raffles', editRaffle.id);
        await updateDoc(raffleRef, raffleData);
      } else {
        // Create new raffle
        await addDoc(collection(db, 'raffles'), {
          ...raffleData,
          createdAt: new Date()
        });
      }
      
      handleCloseDialog();
      refreshData();
    } catch (error) {
      console.error("Error saving raffle:", error);
    }
  };
  
  const handleDeleteRaffle = async (id: string) => {
    if (window.confirm('Вы уверены, что хотите удалить этот розыгрыш?')) {
      try {
        const raffleRef = doc(db, 'raffles', id);
        await deleteDoc(raffleRef);
        refreshData();
      } catch (error) {
        console.error("Error deleting raffle:", error);
      }
    }
  };
  
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'active':
        return theme.palette.success.main;
      case 'completed':
        return theme.palette.info.main;
      case 'draft':
        return theme.palette.warning.main;
      default:
        return theme.palette.error.main;
    }
  };
  
  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'active':
        return 'Активный';
      case 'completed':
        return 'Завершен';
      case 'draft':
        return 'Черновик';
      default:
        return 'Отменен';
    }
  };
  
  // Open car specifications dialog
  const handleOpenCarSpecs = (raffle: Raffle) => {
    setSelectedRaffle(raffle);
    setOpenCarSpecsDialog(true);
  };
  
  // Close car specifications dialog
  const handleCloseCarSpecs = () => {
    setOpenCarSpecsDialog(false);
    setSelectedRaffle(null);
  };
  
  const handleViewCarSpecs = (raffle: Raffle) => {
    if (raffle.carSpecifications) {
      setSelectedRaffle(raffle);
      setViewCarSpecsModal(true);
    }
  };
  
  const handleCloseViewCarSpecs = () => {
    setViewCarSpecsModal(false);
  };
  
  return (
    <Box sx={{ maxWidth: 1200, margin: '0 auto', padding: { xs: 2, md: 3 } }}>
      <AdminHeader>
        <Box>
          <Typography variant="h4" component="h1" gutterBottom fontWeight="bold">
            Панель администратора
          </Typography>
          <Typography variant="subtitle1">
            {isCompanyAdmin 
              ? `Управление компанией: ${companies.find(c => c.id === adminCompanyId)?.name || 'Без названия'}`
              : 'Управляйте розыгрышами, компаниями и настройками'}
          </Typography>
        </Box>
        <IconButton color="inherit">
          <Settings />
        </IconButton>
      </AdminHeader>
      
      {/* Табы для разных разделов */}
      <Box sx={{ mb: 3 }}>
        <Tabs 
          value={tabValue}
          onChange={handleTabChange}
          variant="scrollable"
          scrollButtons="auto"
          aria-label="admin tabs"
          sx={{
            '& .MuiTab-root': {
              minWidth: 'auto',
              px: 3,
              py: 2,
            }
          }}
        >
          <Tab 
            icon={<CardGiftcard />} 
            iconPosition="start"
            label="Розыгрыши" 
            id="admin-tab-0" 
          />
          {!isCompanyAdmin && (
            <Tab 
              icon={<DirectionsCar />} 
              iconPosition="start"
              label="Автомобили" 
              id="admin-tab-1" 
            />
          )}
          {!isCompanyAdmin && (
            <Tab 
              icon={<Business />} 
              iconPosition="start"
              label="Компании" 
              id="admin-tab-2" 
            />
          )}
          {isSuperAdmin && (
            <Tab 
              icon={<SupervisorAccount />} 
              iconPosition="start"
              label="Администраторы" 
              id="admin-tab-3" 
            />
          )}
          {isSuperAdmin && (
            <Tab 
              icon={<Storage />} 
              iconPosition="start"
              label="База данных" 
              id="admin-tab-4" 
            />
          )}
          {isSuperAdmin && (
            <Tab 
              icon={<Settings />} 
              iconPosition="start"
              label="Настройки" 
              id="admin-tab-5" 
            />
          )}
        </Tabs>
      </Box>
      
      {/* Раздел статистики (только на вкладке Розыгрыши) */}
      <TabPanel value={tabValue} index={0}>
        {/* Фильтруем розыгрыши только для администратора компании */}
        {isCompanyAdmin && (
          <Typography variant="subtitle1" color="textSecondary" gutterBottom>
            Показаны розыгрыши только вашей компании. 
            У вас нет доступа к просмотру розыгрышей других компаний.
          </Typography>
        )}

        <Typography variant="h5" gutterBottom>
          Сводная статистика
        </Typography>
        
        <GridContainer spacing={3}>
          {statsData.map((stat, index) => (
            <GridItem xs={12} md={4} key={index}>
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <StatsCard>
                  <CardContent sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                    <StatsIcon>
                      {stat.icon}
                    </StatsIcon>
                    <Typography variant="h4" component="div" fontWeight="bold">
                      {stat.value.toLocaleString()}
                    </Typography>
                    <Typography variant="subtitle1" color="textSecondary" gutterBottom>
                      {stat.title}
                    </Typography>
                    <Typography variant="body2" color="textSecondary">
                      {stat.change}
                    </Typography>
                  </CardContent>
                </StatsCard>
              </motion.div>
            </GridItem>
          ))}
        </GridContainer>
        
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mt: 4, mb: 2 }}>
          <Typography variant="h5">
            Список розыгрышей
          </Typography>
          <Button
            variant="contained"
            color="primary"
            startIcon={<Add />}
            onClick={() => handleOpenDialog()}
          >
            Добавить розыгрыш
          </Button>
        </Box>
        
        <TablePaper>
          <TableContainer>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Название</TableCell>
                  <TableCell>Компания</TableCell>
                  <TableCell>Статус</TableCell>
                  <TableCell>Билеты</TableCell>
                  <TableCell>Цена</TableCell>
                  <TableCell align="right">Действия</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {/* Фильтруем розыгрыши по компании, если пользователь админ компании */}
                {raffles
                  .filter(raffle => !isCompanyAdmin || raffle.companyId === adminCompanyId)
                  .map((raffle) => {
                  const company = companies.find(c => c.id === raffle.companyId);
                  return (
                    <TableRow key={raffle.id}>
                      <TableCell>{raffle.title}</TableCell>
                      <TableCell>{company?.name || 'Неизвестно'}</TableCell>
                      <TableCell>
                        <Chip 
                          label={getStatusLabel(raffle.status)} 
                          size="small"
                          sx={{ 
                            backgroundColor: alpha(getStatusColor(raffle.status), 0.1),
                            color: getStatusColor(raffle.status),
                            fontWeight: 'medium'
                          }}
                        />
                      </TableCell>
                      <TableCell>
                        {raffle.ticketsSold}/{raffle.totalTickets}
                      </TableCell>
                      <TableCell>
                        {raffle.price.toLocaleString()} ₽
                      </TableCell>
                      <TableCell align="right">
                        <Box sx={{ display: 'flex', justifyContent: 'flex-end' }}>
                          <IconButton 
                            size="small" 
                            color="primary"
                            onClick={() => handleOpenDialog(raffle)}
                          >
                            <Edit />
                          </IconButton>
                          
                          {raffle.itemType === 'cars' && (
                            <IconButton 
                              size="small" 
                              color="secondary"
                              onClick={() => handleOpenCarSpecs(raffle)}
                            >
                              <CarRental />
                            </IconButton>
                          )}
                          
                          {raffle.carSpecifications && (
                            <IconButton 
                              size="small" 
                              color="info"
                              onClick={() => handleViewCarSpecs(raffle)}
                            >
                              <Visibility />
                            </IconButton>
                          )}
                          
                          <IconButton 
                            size="small" 
                            color="error"
                            onClick={() => handleDeleteRaffle(raffle.id)}
                          >
                            <Delete />
                          </IconButton>
                        </Box>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </TableContainer>
        </TablePaper>
      </TabPanel>
      
      {/* Вкладка для управления автомобилями */}
      <TabPanel value={tabValue} index={1}>
        {!isCompanyAdmin && (
          <CarSpecificationsForm />
        )}
      </TabPanel>
      
      {/* Вкладка для управления компаниями */}
      <TabPanel value={tabValue} index={2}>
        {!isCompanyAdmin && (
          <CompaniesManager />
        )}
      </TabPanel>
      
      {/* Вкладка для управления администраторами */}
      <TabPanel value={tabValue} index={3}>
        {isSuperAdmin && (
          <AdminsManager isSuperAdmin={true} />
        )}
      </TabPanel>
      
      {/* Вкладка для управления базой данных */}
      <TabPanel value={tabValue} index={4}>
        {isSuperAdmin && (
          <DatabaseMigration />
        )}
      </TabPanel>
      
      {/* Вкладка для настроек приложения */}
      <TabPanel value={tabValue} index={5}>
        {isSuperAdmin && (
          <AppSettingsForm />
        )}
      </TabPanel>
      
      {/* Диалог создания/редактирования розыгрыша */}
      <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="md" fullWidth>
        <DialogTitle>
          {editRaffle ? 'Редактирование розыгрыша' : 'Создание нового розыгрыша'}
        </DialogTitle>
        <DialogContent>
          <Grid container spacing={2} sx={{ mt: 1 }}>
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Название розыгрыша"
                name="title"
                value={form.title}
                onChange={handleFormChange}
                variant="outlined"
                margin="normal"
              />
            </Grid>
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="URL изображения"
                name="image"
                value={form.image}
                onChange={handleFormChange}
                variant="outlined"
                margin="normal"
              />
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Описание"
                name="description"
                value={form.description}
                onChange={handleFormChange}
                variant="outlined"
                margin="normal"
                multiline
                rows={4}
              />
            </Grid>
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Количество билетов"
                name="totalTickets"
                value={form.totalTickets}
                onChange={handleFormChange}
                variant="outlined"
                margin="normal"
                type="number"
              />
            </Grid>
            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Цена билета"
                name="price"
                value={form.price}
                onChange={handleFormChange}
                variant="outlined"
                margin="normal"
                type="number"
              />
            </Grid>
            <Grid item xs={12} md={4}>
              <FormControl fullWidth margin="normal">
                <InputLabel id="status-label">Статус</InputLabel>
                <Select
                  labelId="status-label"
                  name="status"
                  value={form.status}
                  onChange={handleSelectChange}
                  label="Статус"
                >
                  <MenuItem value="draft">Черновик</MenuItem>
                  <MenuItem value="active">Активный</MenuItem>
                  <MenuItem value="completed">Завершен</MenuItem>
                  <MenuItem value="cancelled">Отменен</MenuItem>
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} md={4}>
              <FormControl fullWidth margin="normal">
                <InputLabel id="company-label">Компания</InputLabel>
                <Select
                  labelId="company-label"
                  name="companyId"
                  value={isCompanyAdmin ? (adminCompanyId || '') : form.companyId}
                  onChange={handleSelectChange}
                  label="Компания"
                  disabled={isCompanyAdmin} // Блокируем выбор компании для админа компании
                >
                  {companies.map(company => (
                    <MenuItem key={company.id} value={company.id}>
                      {company.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} md={4}>
              <TextField
                fullWidth
                label="Дата окончания"
                name="endDate"
                value={form.endDate}
                onChange={handleFormChange}
                variant="outlined"
                margin="normal"
                type="date"
                InputLabelProps={{
                  shrink: true,
                }}
              />
            </Grid>
          </Grid>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog} color="inherit">
            Отмена
          </Button>
          <Button onClick={handleSaveRaffle} variant="contained" color="primary">
            Сохранить
          </Button>
        </DialogActions>
      </Dialog>
      
      {/* Диалог для создания/редактирования спецификаций автомобиля */}
      <Dialog open={openCarSpecsDialog} onClose={handleCloseCarSpecs} maxWidth="lg" fullWidth>
        <DialogTitle>
          Спецификации автомобиля - {selectedRaffle?.title}
        </DialogTitle>
        <DialogContent>
          {selectedRaffle && (
            <CarSpecificationsForm raffleId={selectedRaffle.id} onSaved={handleCloseCarSpecs} />
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseCarSpecs} color="primary">
            Закрыть
          </Button>
        </DialogActions>
      </Dialog>
      
      {/* Модальное окно для просмотра спецификаций автомобиля */}
      <Dialog open={viewCarSpecsModal} onClose={handleCloseViewCarSpecs} maxWidth="md" fullWidth>
        <DialogTitle>
          Характеристики автомобиля - {selectedRaffle?.title}
        </DialogTitle>
        <DialogContent>
          {selectedRaffle?.carSpecifications && (
            <CarSpecificationsModal carSpecs={selectedRaffle.carSpecifications} />
          )}
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseViewCarSpecs} color="primary">
            Закрыть
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default AdminPage;
